    const status = actual <= budget ? 'OK' : 'OVER BY ' + (actual - budget)
    console.log('Budget ' + budget + ': actual ' + actual + ' ' + status)
  }
}

// Test 3: Orphan rescue verification
function testOrphanRescue() {
  console.log('\n=== Orphan Rescue Test ===\n')

  const summary = {
    path: '/test/file.md',
    title: 'Test',
    originalTokens: 1000,
    summaryTokens: 500,
    compressionRatio: 0.5,
    sections: [
