            children: [],
            hasCode: false,
            hasList: false,
            hasTable: false,
          },
        ],
        hasCode: false,
        hasList: false,
        hasTable: false,
      },
    ],
    keyTopics: [],
  }

  // Budget enough for header + children but not parent
  const output = formatSummary(summary, { maxTokens: 100 })
  const hasParent = output.includes('Large Parent')
  const hasChildA = output.includes('Small Child A')
  const hasChildB = output.includes('Small Child B')

  console.log('Parent included: ' + hasParent + ' (expected: false)')
  console.log('Child A included: ' + hasChildA + ' (expected: true)')
  console.log('Child B included: ' + hasChildB + ' (expected: true)')
  console.log()
  console.log('Output:')
  console.log(output)
}

async function main() {
  await testTokenAccuracy()
  testBudgetEnforcement()
  testOrphanRescue()
}

