import { countTokensApprox } from './src/utils/tokens.js'
import { formatSummary } from './src/summarize/formatters.js'

// Test with LONG path/title
const longSummary = {
  path: '/very/long/path/to/deeply/nested/directory/structure/file.md',
  title: 'A Very Long Document Title That Takes Up Many Tokens',
  originalTokens: 1000,
  summaryTokens: 500,
  compressionRatio: 0.5,
  sections: [
    {
      heading: 'Section 1',
      level: 2,
      originalTokens: 200,
      summaryTokens: 100,
      summary: 'This is some content that takes up tokens. '.repeat(5),
      children: [],
      hasCode: false,
      hasList: false,
      hasTable: false,
    },
    {
      heading: 'Section 2',
      level: 2,
      originalTokens: 200,
      summaryTokens: 100,
      summary: 'More content here with additional information. '.repeat(5),
      children: [],
      hasCode: false,
      hasList: false,
      hasTable: false,
    },
  ],
  keyTopics: ['topic1', 'topic2', 'topic3', 'topic4', 'topic5'],
}

console.log('=== Budget Enforcement Test (Long Path/Title) ===\n')

const budgets = [50, 60, 70, 75, 100, 150, 200]
for (const budget of budgets) {
  const output = formatSummary(longSummary, { maxTokens: budget })
  const actual = countTokensApprox(output)
  const status = actual <= budget ? 'OK' : 'OVER BY ' + (actual - budget)
  console.log('Budget ' + budget + ': actual ' + actual + ' ' + status)
}

// Detailed output for budget 50
console.log('\n=== Detailed output for budget 50 ===')
const output50 = formatSummary(longSummary, { maxTokens: 50 })
console.log(output50)
console.log('Actual tokens:', countTokensApprox(output50))

